(Comp: IProtectedComponent) => {
  const routeData = () => {
    return createServerData$(
      async (_, event) => {
        const session = await getSession(event.request, authOpts)
        if (!session || !session.user) {
          throw redirect("/")
        }
        return session
      },
      { key: () => ["auth_user"] }
    )
  }

  return {
    routeData,
    Page: () => {
      const session = useRouteData<typeof routeData>()
      return (
        <Show when={session()} keyed>
          {(sess) => <Comp {...sess} />}
        </Show>
      )
    },
  }
}

() => {
  const [scale, setScale] = useState(changeScale)
  const [logoCount, setLogoCount] = useState(changeLogoCount)

  useEffect(() => {
    // Window resize handling
    function handleEvent() {
      setScale(changeScale)
      setLogoCount(changeLogoCount)
    }

    window.addEventListener("resize", handleEvent)
    return () => window.removeEventListener("resize", handleEvent)
  }, [])

  return (
    <div className="pointer-events-none absolute left-0 top-0 h-full w-full opacity-30">
      {Object.entries(manifest.providersOAuth)
        .sort(() => Math.random() - 0.5)
        .filter((_, i) => i < logoCount!)
        .map(([id, name]) => (
          <Logo providerId={id} name={name} scale={scale} key={id} />
        ))}
    </div>
  )
}

export default function Mattermost<P extends MattermostProfile>(
  config: OAuthUserConfig<P> & { issuer: string }
): OAuthConfig<P> {
  const { issuer, ...rest } = config

  return {
    id: "mattermost",
    name: "Mattermost",
    type: "oauth",
    client: { token_endpoint_auth_method: "client_secret_post" },
    token: `${issuer}/oauth/access_token`,
    authorization: `${issuer}/oauth/authorize`,
    userinfo: `${issuer}/api/v4/users/me`,
    profile(profile) {
      return {
        id: profile.id,
        name: profile.username ?? `${profile.first_name} ${profile.last_name}`,
        email: profile.email,
        image: null,
      }
    },
    style: { bg: "#000", text: "#fff" },
    options: rest,
  }
}

